// Extrai os dados relevantes do payload de webhook da Evolution API.
// Formato defensivo: cobre tanto `message.conversation` (texto simples)
// quanto `message.extendedTextMessage.text` (texto com contexto/resposta).
const body = $input.first().json.body || $input.first().json;
const data = body.data || body;

const remoteJid = data?.key?.remoteJid || "";
const numero = remoteJid.replace("@s.whatsapp.net", "").replace("@g.us", "");
const fromMe = !!data?.key?.fromMe;
const texto =
  data?.message?.conversation ||
  data?.message?.extendedTextMessage?.text ||
  data?.message?.imageMessage?.caption ||
  "";
const temImagem = !!data?.message?.imageMessage;
const nomeCliente = data?.pushName || "Cliente";
const evolutionMessageId = data?.key?.id || "";
const timestamp = data?.messageTimestamp ? Number(data.messageTimestamp) * 1000 : Date.now();
const companyId = $env.DEFAULT_COMPANY_ID || "cutefood-cwb";
// ID da conversa: como o mesmo telefone pode, em teoria, existir em mais
// de uma empresa, o ID do documento é composto (ver docs/arquitetura/CF-070).
const conversationId = `${companyId}_${numero}`;

return [
  {
    json: {
      numero,
      companyId,
      conversationId,
      fromMe,
      texto,
      temImagem,
      nomeCliente,
      evolutionMessageId,
      timestamp,
    },
  },
];

// A conversa usa o próprio número de telefone como ID do documento — ver
// docs/integracoes/claude.md para a justificativa dessa escolha.
// Se o GET anterior devolveu 404, a conversa ainda não existe.
const resposta = $input.first().json;
const mensagem = $('Receber mensagem').first().json;

const conversaExiste = !resposta.error && !!resposta.fields;
const briefingId = conversaExiste && resposta.fields.briefingId ? resposta.fields.briefingId.stringValue : null;

return [
  {
    json: {
      ...mensagem,
      conversaExiste,
      briefingId,
    },
  },
];

// Monta o array de mensagens para o Claude: prompt de sistema (baseado em
// docs/prompts/CF-040-prompt-mestre.md) + histórico da coleção `messages`
// + a mensagem nova recebida agora. Também repassa o snapshot atual do
// briefing (se existir) para o Claude não perder o que já foi coletado.
const dadosMensagem = $('Resolver estado').first().json;
const historicoRaw = $('Buscar mensagens anteriores').first().json || [];

function lerCampo(fields, nome, padrao = "") {
  if (!fields || !fields[nome]) return padrao;
  const v = fields[nome];
  return v.stringValue ?? v.integerValue ?? padrao;
}

const historico = (Array.isArray(historicoRaw) ? historicoRaw : [])
  .filter((r) => r.document)
  .map((r) => {
    const f = r.document.fields;
    return { autor: lerCampo(f, "autor"), texto: lerCampo(f, "texto") };
  });

let briefingAtual = {};
try {
  const briefingNode = $('Buscar briefing atual').first();
  if (briefingNode && briefingNode.json && briefingNode.json.fields) {
    const f = briefingNode.json.fields;
    briefingAtual = {
      evento: lerCampo(f, "evento"),
      tema: lerCampo(f, "tema"),
      data: lerCampo(f, "data"),
      quantidade: lerCampo(f, "quantidade"),
      sabores: lerCampo(f, "sabores"),
      orcamento: lerCampo(f, "orcamento"),
      entrega: lerCampo(f, "entrega"),
      status: lerCampo(f, "status", "Novo"),
      complexidade: lerCampo(f, "complexidade", "Simples"),
    };
  }
} catch (e) {
  briefingAtual = {};
}

const systemPrompt = `Você é a assistente virtual da CuteFood. Siga rigorosamente o Prompt Mestre do projeto (docs/prompts/CF-040-prompt-mestre.md): seja simpática, elegante, organizada, paciente, consultiva e acolhedora — nunca robótica. Conduza o briefing, uma pergunta por vez quando necessário, confirme dados importantes, registre referências visuais quando mencionadas. NUNCA negocie preço, prazo, nem aprove pedidos — essas decisões são sempre da confeiteira. Responda SEMPRE em um JSON válido, sem nenhum texto fora do JSON, no formato exato:
{
  "resposta": "texto da mensagem a ser enviada ao cliente pelo WhatsApp",
  "briefing": {
    "evento": "...", "tema": "...", "data": "AAAA-MM-DD ou vazio", "quantidade": "...", "sabores": "...", "orcamento": "...", "entrega": "...", "status": "Novo|Briefing|Orçamento|Aprovado|Produção|Finalizado", "complexidade": "Simples|Média|Alta"
  }
}
Mantenha em "briefing" todos os campos já conhecidos (não apague informações já coletadas em turnos anteriores) e atualize apenas o que mudou nesta mensagem.`;

const mensagensClaude = [
  ...historico.map((h) => ({ role: h.autor === "ia" ? "assistant" : "user", content: h.texto })),
  { role: "user", content: dadosMensagem.texto },
];

return [
  {
    json: {
      ...dadosMensagem,
      briefingAtual,
      systemPrompt,
      mensagensClaude,
    },
  },
];

// A resposta do Claude vem em content[0].text — pedimos, no prompt de
// sistema, que esse texto seja um JSON com { resposta, briefing }.
const contexto = $('Montar contexto').first().json;
const claudeOut = $input.first().json;
const textoBruto = claudeOut?.content?.[0]?.text || "{}";

let parsed;
try {
  parsed = JSON.parse(textoBruto);
} catch (e) {
  // Se o Claude não devolveu um JSON válido, cai para uma resposta segura
  // em vez de quebrar o workflow.
  parsed = {
    resposta: "Só um instante, já te retorno com mais detalhes! 💛",
    briefing: contexto.briefingAtual || {},
  };
}

return [
  {
    json: {
      ...contexto,
      respostaTexto: parsed.resposta,
      briefingNovo: { ...contexto.briefingAtual, ...(parsed.briefing || {}) },
    },
  },
];

// Extrai o ID do briefing recém-criado a partir do `name` retornado pela
// API REST do Firestore (mesmo padrão usado em workflows/briefing.json).
const nomeCompleto = $input.first().json.name || "";
const partes = nomeCompleto.split("/");
const novoBriefingId = partes[partes.length - 1];
const contexto = $('Receber resposta').first().json;

return [{ json: { ...contexto, briefingId: novoBriefingId } }];
